import React, { useState } from 'react';
import { useLanguage } from '../LanguageContext';
import './Login.css';

function Login({ onLogin }) {
  const { t } = useLanguage();
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [isLoading, setIsLoading] = useState(false);

  const handleSubmit = async (e) => {
    e.preventDefault();
    
    // BUG: No client-side validation (intentional)
    setIsLoading(true);
    try {
      await onLogin({ username, password });
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="login-container">
      <div className="login-card">
        <h2>{t('login')}</h2>
        <form onSubmit={handleSubmit}>
          <div className="form-group">
            <label htmlFor="username">{t('username')}</label>
            <input
              type="text"
              id="username"
              value={username}
              onChange={(e) => setUsername(e.target.value)}
              placeholder={t('enterUsername')}
              disabled={isLoading}
            />
          </div>

          <div className="form-group">
            <label htmlFor="password">{t('password')}</label>
            <input
              type="password"
              id="password"
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              placeholder={t('enterPassword')}
              disabled={isLoading}
            />
          </div>

          <button type="submit" disabled={isLoading}>
            {isLoading ? t('loggingIn') : t('loginButton')}
          </button>
        </form>

        {/* Testing credentials - BUG: Showing test credentials in production */}
        <div className="test-credentials">
          <h4>{t('testCredentials')}</h4>
          <p><strong>{t('enabledUser')}</strong><br /> testuser / password123</p>
          <p><strong>{t('disabledUser')}</strong><br /> disableduser / password123</p>
          <p><strong>{t('admin')}:</strong><br /> admin / admin123</p>
        </div>
      </div>
    </div>
  );
}

export default Login;
